"""
Main entry point for the LLM code generation and coverage pipeline.

This module orchestrates the end‑to‑end execution for a batch of tasks:
  * Loads the task catalog (generated by ``code/dataset_loader.py``)
  * Generates code for each task using the selected model
  * Executes pytest‑based coverage measurement
  * Persists coverage results or error reports to ``data/coverage_reports/``

The script can be invoked from the command line:

    python code/main.py --dataset mbpp --model gpt-4 --batch-size 10

Additional legacy arguments (``--num-tasks`` and ``--output-dir``) are accepted
for backward compatibility but are ignored by the current implementation.
"""

import argparse
import json
import logging
import os
from datetime import datetime
from pathlib import Path
from typing import Any, List, Dict

# --------------------------------------------------------------------------- #
# Public API surface (must match what other modules expect)
# --------------------------------------------------------------------------- #
__all__ = [
    "setup_logger",
    "load_task_catalog",
    "save_error_report",
    "process_single_task",
    "run_batch_pipeline",
    "run_sensitivity_analysis_wrapper",
    "run_analysis_pipeline_wrapper",
    "main",
]

# --------------------------------------------------------------------------- #
# Logger utilities – re‑exported from ``code/logger_config.py`` for convenience
# --------------------------------------------------------------------------- #
from logger_config import setup_logger as _setup_logger

def setup_logger() -> None:
    """Configure the pipeline logger."""
    _setup_logger()

# --------------------------------------------------------------------------- #
# Helper: load the normalized task catalog produced by ``dataset_loader.py``.
# --------------------------------------------------------------------------- #
def load_task_catalog(dataset: str = "mbpp") -> List[Dict[str, Any]]:
    """
    Load the processed task catalog.

    Parameters
    ----------
    dataset: str
        Identifier of the dataset to load (currently unused – the catalog is
        dataset‑agnostic because ``dataset_loader`` normalises both MBPP and
        HumanEval into a single JSON file).

    Returns
    -------
    List[Dict[str, Any]]
        List of task entries.  Each entry must contain at least a ``task_id`` key.
    """
    catalog_path = Path("data/benchmarks/processed/catalog.json")
    if not catalog_path.is_file():
        logging.error("Task catalog not found at %s", catalog_path)
        return []
    try:
        with catalog_path.open("r", encoding="utf-8") as f:
            catalog = json.load(f)
        if not isinstance(catalog, list):
            logging.error("Catalog JSON is not a list – got %s", type(catalog))
            return []
        return catalog
    except Exception as e:
        logging.exception("Failed to read task catalog: %s", e)
        return []

# --------------------------------------------------------------------------- #
# Helper: write a JSON error report for a failed task.
# --------------------------------------------------------------------------- #
def save_error_report(task_id: str, error_message: str) -> None:
    """
    Persist an error report for a task that could not be processed.

    The JSON file is written to ``data/coverage_reports/{task_id}.json`` and
    follows the schema required by the specification.

    Parameters
    ----------
    task_id: str
        Identifier of the task (e.g. ``HumanEval/0``).
    error_message: str
        Human‑readable description of the failure.
    """
    report = {
        "task_id": task_id,
        "status": "failed",
        "error_message": error_message,
        "timestamp": datetime.utcnow().isoformat() + "Z",
    }
    out_dir = Path("data/coverage_reports")
    out_dir.mkdir(parents=True, exist_ok=True)
    out_path = out_dir / f"{task_id}.json"
    try:
        with out_path.open("w", encoding="utf-8") as f:
            json.dump(report, f, indent=2)
        logging.info("Wrote error report for %s to %s", task_id, out_path)
    except Exception as e:
        logging.exception("Failed to write error report for %s: %s", task_id, e)

# --------------------------------------------------------------------------- #
# Core per‑task processing logic.
# --------------------------------------------------------------------------- #
def process_single_task(task_id: str, model: str) -> None:
    """
    Generate code for a single task and run coverage measurement.

    Any exception (including ``SyntaxError``) is caught, logged and an error
    report is written so the batch pipeline can continue processing other
    tasks.

    Parameters
    ----------
    task_id: str
        Identifier of the task to process.
    model: str
        Name of the model to pass to ``llm_generator.generate_code``.
    """
    from llm_generator import generate_code
    from coverage_runner import run_coverage, save_coverage_report

    try:
        # ------------------------------------------------------------------- #
        # 1️⃣  LLM code generation
        # ------------------------------------------------------------------- #
        logging.info("Generating code for task %s using model %s", task_id, model)
        generated_path = generate_code(task_id, model)
        if not generated_path or not Path(generated_path).exists():
            raise RuntimeError(f"Generation returned an invalid path: {generated_path}")

        # ------------------------------------------------------------------- #
        # 2️⃣  Coverage execution
        # ------------------------------------------------------------------- #
        logging.info("Running coverage for task %s", task_id)
        coverage_result = run_coverage(task_id)

        # ``run_coverage`` returns a dict with at least ``line_coverage`` and
        # ``branch_coverage`` (the latter may be ``\"N/A\"`` for HumanEval).
        if not isinstance(coverage_result, dict):
            raise RuntimeError("Coverage runner returned a non‑dict result")

        # ------------------------------------------------------------------- #
        # 3️⃣  Persist coverage report
        # ------------------------------------------------------------------- #
        save_coverage_report(task_id, coverage_result)
        logging.info("Successfully processed task %s", task_id)

    except SyntaxError as se:
        logging.error("SyntaxError while processing %s: %s", task_id, se)
        save_error_report(task_id, f"SyntaxError: {se}")
    except Exception as ex:
        logging.exception("Unexpected error while processing %s", task_id)
        save_error_report(task_id, f"{type(ex).__name__}: {ex}")

# --------------------------------------------------------------------------- #
# Batch orchestration – respects ``batch_size`` and optional ``num_tasks`` limit.
# --------------------------------------------------------------------------- #
def run_batch_pipeline(
    tasks: List[Dict[str, Any]],
    model: str,
    batch_size: int = 10,
    num_tasks: int | None = None,
) -> None:
    """
    Execute ``process_single_task`` for a collection of tasks.

    Parameters
    ----------
    tasks: List[Dict[str, Any]]
        The full task catalog (list of dicts with at least ``task_id``).
    model: str
        Model name to be used for generation.
    batch_size: int
        Number of tasks to handle in each internal batch (does not affect
        overall semantics – it only controls logging granularity).
    num_tasks: Optional[int]
        If provided, truncate the task list to this many entries.
    """
    if num_tasks is not None:
        tasks = tasks[:num_tasks]

    total = len(tasks)
    logging.info("Starting batch pipeline: %d tasks, batch size %d, model %s", total, batch_size, model)

    for start in range(0, total, batch_size):
        batch = tasks[start : start + batch_size]
        logging.info("Processing batch %d – %d (inclusive)", start + 1, start + len(batch))
        for entry in batch:
            task_id = entry.get("task_id") if isinstance(entry, dict) else str(entry)
            if not task_id:
                logging.warning("Skipping malformed catalog entry: %s", entry)
                continue
            process_single_task(task_id, model)

    logging.info("Batch pipeline completed for %d tasks", total)

# --------------------------------------------------------------------------- #
# Wrappers for downstream analysis stages – delegated to existing modules.
# --------------------------------------------------------------------------- #
def run_sensitivity_analysis_wrapper() -> None:
    """
    Entry point used by downstream scripts / notebooks to trigger the
    sensitivity analysis defined in ``code/sensitivity_analyzer.py``.
    """
    from sensitivity_analyzer import main as sensitivity_main

    logging.info("Running sensitivity analysis wrapper")
    sensitivity_main()

def run_analysis_pipeline_wrapper() -> None:
    """
    Entry point used by downstream scripts / notebooks to trigger the full
    statistical analysis pipeline defined in ``code/analyzer.py``.
    """
    from analyzer import main as analyzer_main

    logging.info("Running full analysis pipeline wrapper")
    analyzer_main()

# --------------------------------------------------------------------------- #
# Argument parsing – adds the arguments required by the task description.
# --------------------------------------------------------------------------- #
def _parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Orchestrate LLM code generation and coverage measurement."
    )
    parser.add_argument(
        "--dataset",
        type=str,
        default="mbpp",
        help="Which benchmark dataset to use (e.g., mbpp, humaneval).",
    )
    parser.add_argument(
        "--model",
        type=str,
        default="gpt-4",
        help="Model identifier passed to the LLM generator.",
    )
    parser.add_argument(
        "--batch-size",
        type=int,
        default=10,
        help="Number of tasks processed per internal batch.",
    )
    # Backwards‑compatibility: the original quick‑start script used these flags.
    parser.add_argument(
        "--num-tasks",
        type=int,
        default=None,
        help="(Legacy) Limit the total number of tasks processed.",
    )
    parser.add_argument(
        "--output-dir",
        type=str,
        default=None,
        help="(Legacy) Unused – retained so older scripts do not fail.",
    )
    return parser.parse_args()

# --------------------------------------------------------------------------- #
# Main entry point – wires everything together.
# --------------------------------------------------------------------------- #
def main() -> None:
    """
    Execute the full pipeline based on command‑line arguments.
    """
    args = _parse_args()
    setup_logger()

    logging.info(
        "Pipeline start – dataset=%s, model=%s, batch_size=%d, num_tasks=%s",
        args.dataset,
        args.model,
        args.batch_size,
        str(args.num_tasks) if args.num_tasks is not None else "None",
    )

    catalog = load_task_catalog(dataset=args.dataset)
    if not catalog:
        logging.error("No tasks found in the catalog – aborting.")
        return

    run_batch_pipeline(
        tasks=catalog,
        model=args.model,
        batch_size=args.batch_size,
        num_tasks=args.num_tasks,
    )

    logging.info("Pipeline finished successfully.")

# --------------------------------------------------------------------------- #
# Allow ``python -m code.main`` as well as direct script execution.
# --------------------------------------------------------------------------- #
if __name__ == "__main__":
    main()